#include <stdio.h>
#define DIM 5

int main() {
    int i, j;
    int matrica[DIM][DIM] = {
        {1, 2, 3, 4, 5},
        {6, 7, 8, 9, 9},
        {8, 7, 6, 5, 4},
        {3, 2, 1, 1, 2},
        {3, 4, 5, 6, 7}
    };

    /* Postavljanje elemenata ispod dijagonale na nulu */
    for (i = 0; i < DIM; i++) {
        for (j = 0; j < DIM; j++) {
            if (i > j)
                matrica[i][j] = 0;
        }
    }

    printf("Matrica sada glasi:\n");
    for (i = 0; i < DIM; i++) {
        for (j = 0; j < DIM; j++) {
            printf("%d ", matrica[i][j]);
        }
        printf("\n");
    }
    return 0;
}
